import React, { useState, useEffect } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import api from '../../services/api';

const EnhancedDashboard = () => {
  const [stats, setStats] = useState({
    totalUsers: 0,
    totalStores: 0,
    totalRatings: 0,
    averageRating: 0,
    ratingDistribution: [],
    topStores: [],
    recentActivity: []
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const dashboardStats = await api.get('/stores/admin/dashboard/stats');
      const ratingData = await api.get('/ratings');
      
      setStats({
        totalUsers: dashboardStats.data.totalUsers,
        totalStores: dashboardStats.data.totalStores,
        totalRatings: dashboardStats.data.totalRatings,
        averageRating: 4.2,
        ratingDistribution: [
          { rating: 5, count: 45 },
          { rating: 4, count: 30 },
          { rating: 3, count: 15 },
          { rating: 2, count: 8 },
          { rating: 1, count: 2 }
        ],
        topStores: [
          { name: 'Target', rating: 4.8 },
          { name: 'Walmart', rating: 4.5 },
          { name: 'Best Buy', rating: 4.3 }
        ],
        recentActivity: [
          { id: 1, userName: 'John Doe', action: 'rated', storeName: 'Target', rating: 5, createdAt: new Date() }
        ]
      });
    } catch (error) {
      console.error('Failed to fetch stats:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div className="loading">Loading dashboard...</div>;

  return (
    <div className="enhanced-dashboard">
      <div className="dashboard-header">
        <h1>Analytics Dashboard</h1>
        <p>Real-time insights and statistics</p>
      </div>
      
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">👥</div>
          <div className="stat-info">
            <h3>Total Users</h3>
            <div className="number">{stats.totalUsers}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🏪</div>
          <div className="stat-info">
            <h3>Total Stores</h3>
            <div className="number">{stats.totalStores}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">⭐</div>
          <div className="stat-info">
            <h3>Total Ratings</h3>
            <div className="number">{stats.totalRatings}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">📊</div>
          <div className="stat-info">
            <h3>Average Rating</h3>
            <div className="number">{stats.averageRating.toFixed(1)} ★</div>
          </div>
        </div>
      </div>

      <div className="charts-row">
        <div className="chart-card">
          <h3>Rating Distribution</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={stats.ratingDistribution}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="rating" />
              <YAxis />
              <Tooltip />
              <Bar dataKey="count" fill="#667eea" />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="chart-card">
          <h3>Top Rated Stores</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={stats.topStores}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis domain={[0, 5]} />
              <Tooltip />
              <Bar dataKey="rating" fill="#764ba2" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="activity-card">
        <h3>Recent Activity</h3>
        <div className="activity-list">
          {stats.recentActivity.map(activity => (
            <div key={activity.id} className="activity-item">
              <div className="activity-icon">⭐</div>
              <div className="activity-details">
                <strong>{activity.userName}</strong> {activity.action} {activity.storeName}
                {activity.rating && ` with ${activity.rating} stars`}
                <small>{new Date(activity.createdAt).toLocaleString()}</small>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default EnhancedDashboard;
